<template><div><PageHeader eyebrow="ADMIN / RELATIONS" title="关系管理" description="维护作品分类、角色关系、角色演员和人物作品关联"/><el-tabs v-model="tab"><el-tab-pane label="作品分类" name="workCategory"><RelationForm :fields="['workId','categoryId']" @create="workApi.bindCategory" @remove="removeWorkCategory"/></el-tab-pane><el-tab-pane label="角色关系" name="characterRelation"><RelationForm :fields="['sourceId','targetId','relationType']" @create="characterApi.createRelation" :remove-by-id="characterApi.removeRelation"/></el-tab-pane><el-tab-pane label="作品-角色-演员" name="actor"><RelationForm :fields="['workId','characterId','personId','roleType']" @create="characterApi.bindActor" @remove="characterApi.unbindActor"/></el-tab-pane><el-tab-pane label="人物-作品" name="personWork"><RelationForm :fields="['personId','workId','roleType']" @create="personApi.bindWork" @remove="personApi.unbindWork"/></el-tab-pane></el-tabs></div></template>
<script setup>import { defineComponent,h,reactive,ref } from 'vue';import { ElButton,ElForm,ElFormItem,ElInput,ElMessage } from 'element-plus';import PageHeader from '../../components/PageHeader.vue';import { workApi } from '../../api/work';import { characterApi } from '../../api/character';import { personApi } from '../../api/person';const tab=ref('workCategory');const removeWorkCategory=(data)=>workApi.unbindCategory(data.workId,data.categoryId);const RelationForm=defineComponent({props:{fields:Array,removeById:Function},emits:['create','remove'],setup(props,{emit}){const form=reactive({}),removeId=ref('');const create=async()=>{await new Promise((resolve,reject)=>emit('create',{...form},resolve,reject));ElMessage.success('关联创建成功')};const remove=async()=>{if(props.removeById)await props.removeById(removeId.value);else emit('remove',{...form});ElMessage.success('关联删除成功')};return()=>h('div',{class:'relation-workbench'},[h(ElForm,{labelPosition:'top',class:'form-grid'},()=>props.fields.map(f=>h(ElFormItem,{label:f,key:f},()=>h(ElInput,{modelValue:form[f], 'onUpdate:modelValue':v=>form[f]=v})))),h('div',{class:'action-row'},[h(ElButton,{type:'primary',onClick:async()=>{emit('create',{...form});ElMessage.success('请求已发送')}},()=> '创建关联'),props.removeById?h(ElInput,{modelValue:removeId.value,placeholder:'输入关系 ID 删除',style:'width:240px','onUpdate:modelValue':v=>removeId.value=v}):null,h(ElButton,{type:'danger',onClick:remove},()=> '删除关联')])])}})</script>
